<?php
namespace App\Models;
use App\Models\Concerns\BelongsToTenant;use Illuminate\Database\Eloquent\Concerns\HasUlids;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\BelongsTo;
class JournalEntryLine extends Model{use BelongsToTenant,HasUlids;public $timestamps=false;protected $fillable=['cooperative_id','journal_entry_id','ledger_account_id','member_id','loan_id','branch_id','debit_minor','credit_minor','memo','dimensions','created_at'];protected function casts():array{return ['debit_minor'=>'integer','credit_minor'=>'integer','dimensions'=>'array','created_at'=>'datetime'];}protected static function booted():void{static::updating(fn()=>throw new \LogicException('Posted journal lines are immutable.'));static::deleting(fn()=>throw new \LogicException('Posted journal lines cannot be deleted.'));}public function entry():BelongsTo{return $this->belongsTo(JournalEntry::class,'journal_entry_id');}public function account():BelongsTo{return $this->belongsTo(LedgerAccount::class,'ledger_account_id');}}
